// src/pages/HomePage.js

import React from "react";
import { useNavigate } from "react-router-dom";

function HomePage() {
  const navigate = useNavigate();

  const features = [
    { label: "Translate Text", path: "/translate" },
    { label: "Summarize Text", path: "/summarize" },
    { label: "Market News & Summary", path: "/market-news" },
    { label: "Stock Search", path: "/stock-search" },
    {label:"Stock Details", path: "/stock-details"},
    { label: "Screener", path: "/screener" },
    { label: "Comparison", path: "/compare" },
    { label: "News Impact Prediction", path: "/news-impact" },
    { label: "Keyword Extraction", path: "/keywords" },
    { label: "Named Entity Recognition", path: "/ner" },
  ];

  const pageStyle = {
    maxWidth: "600px",
    margin: "50px auto",
    textAlign: "center",
    fontFamily: "Arial, sans-serif",
  };

  const buttonStyle = {
    display: "block",
    width: "100%",
    padding: "10px",
    margin: "10px 0",
    fontSize: "16px",
    backgroundColor: "#007bff",
    color: "#fff",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
  };

  const titleStyle = {
    fontSize: "28px",
    fontWeight: "bold",
    marginBottom: "20px",
  };

  const descStyle = {
    fontSize: "16px",
    marginBottom: "30px",
    color: "#555",
  };

  return (
    <div style={pageStyle}>
      <h1 style={titleStyle}>Stock Insight AI</h1>
      <p style={descStyle}>
        Your AI-powered toolkit for stock market analysis. Select a feature below to get started.
      </p>

      {features.map((feature) => (
        <button
          key={feature.path}
          style={buttonStyle}
          onClick={() => navigate(feature.path)}
        >
          {feature.label}
        </button>
      ))}
    </div>
  );
}

export default HomePage;
